    /**
     * Estandariza los datos crudos del sensor usando Z-Score normalization.
     * La operación se realiza in-place para ahorrar memoria (Gama Baja).
     */
    fun standardizeInPlace(rawData: FloatArray) {
        if (rawData.size != 453) return

        for (i in rawData.indices) {
            val divisor = if (stds[i] == 0f) 1f else stds[i]
            rawData[i] = (rawData[i] - means[i]) / divisor
        }
    }
}